/* Cosmic Style Studio — NPC 9999012
 * Free hair, face, skin, and eye color changer for all players.
 * Located in Henesys (100000000).
 *
 * Costs 50,000 meso per change (affordable but not free).
 * Uses cm.getCosmeticItem() to validate IDs exist in the WZ data.
 *
 * Generated by modules/maplestory/custom-dailies.js (cosmetic shop)
 */

var status = 0;
var beauty = 0;
var price = 50000;

// Male hairstyles (v83 standard set)
var maleHair = [30000, 30010, 30020, 30030, 30040, 30050, 30060, 30070, 30080, 30090,
    30110, 30120, 30130, 30140, 30150, 30160, 30170, 30180, 30190, 30200,
    30210, 30220, 30230, 30240, 30250, 30260, 30270, 30280, 30290, 30300,
    30310, 30320, 30330, 30340, 30350, 30360, 30370, 30400, 30410, 30420,
    30440, 30450, 30460, 30470, 30480, 30490, 30510, 30520, 30530, 30540];

// Female hairstyles
var femaleHair = [31000, 31010, 31020, 31030, 31040, 31050, 31060, 31070, 31080, 31090,
    31100, 31110, 31120, 31130, 31140, 31150, 31160, 31170, 31180, 31190,
    31200, 31210, 31220, 31230, 31240, 31250, 31260, 31270, 31280, 31290,
    31300, 31310, 31320, 31330, 31340, 31350, 31400, 31410, 31420, 31440,
    31450, 31460, 31470, 31480, 31490, 31510, 31520, 31530, 31540, 31550];

// Male faces
var maleFace = [20000, 20001, 20002, 20003, 20004, 20005, 20006, 20007, 20008, 20009,
    20010, 20011, 20012, 20013, 20014, 20015, 20016, 20017, 20018, 20019,
    20020, 20021, 20022, 20023, 20024, 20025, 20026, 20027, 20028, 20029];

// Female faces
var femaleFace = [21000, 21001, 21002, 21003, 21004, 21005, 21006, 21007, 21008, 21009,
    21010, 21011, 21012, 21013, 21014, 21016, 21017, 21018, 21019, 21020,
    21021, 21022, 21023, 21024, 21025, 21026, 21027, 21029, 21030];

// Skin colors
var skinColors = [0, 1, 2, 3, 4, 5, 9, 10];

var chosenList = [];
var hairColorList = [];
var faceColorList = [];

function pushIfItemExists(array, itemid) {
    if ((itemid = cm.getCosmeticItem(itemid)) != -1 && !cm.isCosmeticEquipped(itemid)) {
        array.push(itemid);
    }
}

function start() {
    status = 0;
    beauty = 0;
    chosenList = [];
    hairColorList = [];
    faceColorList = [];

    var menu = "Welcome to the #bCosmic Style Studio#k!\r\n";
    menu += "A makeover costs #r" + price + " mesos#k.\r\n\r\n";
    menu += "#L0##bChange Skin Color#l\r\n";

    if (cm.getPlayer().isMale()) {
        menu += "#L1##bChange Hairstyle#l\r\n";
    } else {
        menu += "#L5##bChange Hairstyle#l\r\n";
    }

    menu += "#L2##bChange Hair Color#l\r\n";

    if (cm.getPlayer().isMale()) {
        menu += "#L3##bChange Face#l\r\n";
    } else {
        menu += "#L6##bChange Face#l\r\n";
    }

    menu += "#L4##bChange Eye Color#l\r\n";

    cm.sendSimple(menu);
}

function action(mode, type, selection) {
    if (mode != 1) {
        cm.dispose();
        return;
    }
    status++;

    if (status == 1) {
        beauty = selection;

        if (cm.getMeso() < price) {
            cm.sendOk("You need at least #r" + price + " mesos#k for a makeover. Come back when you can afford it!");
            cm.dispose();
            return;
        }

        if (selection == 0) {
            // Skin
            cm.sendStyle("Pick a skin color:", skinColors);
        } else if (selection == 1 || selection == 5) {
            // Hair (male=1, female=5)
            var hairList = (selection == 1) ? maleHair : femaleHair;
            for (var i = 0; i < hairList.length; i++) {
                pushIfItemExists(chosenList, hairList[i]);
            }
            if (chosenList.length == 0) {
                cm.sendOk("No hairstyles available right now. Try again later!");
                cm.dispose();
                return;
            }
            cm.sendStyle("Pick a hairstyle:", chosenList);
        } else if (selection == 2) {
            // Hair color
            var baseHair = parseInt(cm.getPlayer().getHair() / 10) * 10;
            for (var k = 0; k < 8; k++) {
                pushIfItemExists(hairColorList, baseHair + k);
            }
            if (hairColorList.length == 0) {
                cm.sendOk("No hair colors available for your current style.");
                cm.dispose();
                return;
            }
            cm.sendStyle("Pick a hair color:", hairColorList);
        } else if (selection == 3 || selection == 6) {
            // Face (male=3, female=6)
            var faceList = (selection == 3) ? maleFace : femaleFace;
            for (var j = 0; j < faceList.length; j++) {
                pushIfItemExists(chosenList, faceList[j]);
            }
            if (chosenList.length == 0) {
                cm.sendOk("No face styles available right now. Try again later!");
                cm.dispose();
                return;
            }
            cm.sendStyle("Pick a face:", chosenList);
        } else if (selection == 4) {
            // Eye/face color
            var baseFace = parseInt(cm.getPlayer().getFace() / 1000) * 1000 + parseInt(cm.getPlayer().getFace() % 100);
            for (var c = 0; c < 9; c++) {
                pushIfItemExists(faceColorList, baseFace + (c * 100));
            }
            if (faceColorList.length == 0) {
                cm.sendOk("No eye colors available for your current face.");
                cm.dispose();
                return;
            }
            cm.sendStyle("Pick an eye color:", faceColorList);
        }

    } else if (status == 2) {
        // Apply the change
        if (beauty == 0) {
            cm.setSkin(skinColors[selection]);
        } else if (beauty == 1 || beauty == 5) {
            cm.setHair(chosenList[selection]);
        } else if (beauty == 2) {
            cm.setHair(hairColorList[selection]);
        } else if (beauty == 3 || beauty == 6) {
            cm.setFace(chosenList[selection]);
        } else if (beauty == 4) {
            cm.setFace(faceColorList[selection]);
        }
        cm.gainMeso(-price);
        cm.sendOk("Looking great! Enjoy your new look. Come back anytime for another makeover!");
        cm.dispose();
    }
}
